{
  "situations": [
    {
      "dialogue": "{{NAME}}, a muda recebe água, sais minerais e luz intensa, mas o sensor indica ausência de CO₂ na câmara. Mesmo iluminada, ela parou de aumentar sua massa.",
      "imagePrompt": "Muda verde em uma câmara transparente, raízes em solução com água e sais minerais, lâmpada acesa e visor legível indicando “CO₂: ausente”; balança mostra massa sem alteração.",
      "options": [
        {
          "feedback": "O CO₂ fornece carbono para a planta formar matéria orgânica. A luz fornece energia, mas não substitui essa matéria-prima.",
          "isCorrect": true,
          "text": "Restabelecer o CO₂"
        },
        {
          "feedback": "Mais luz aumentaria a oferta de energia, mas o problema indicado é a ausência de carbono. É preciso restabelecer o CO₂, que fornece matéria para produzir compostos orgânicos.",
          "isCorrect": false,
          "text": "Aumentar a luz"
        },
        {
          "feedback": "Aquecer a câmara não fornece o carbono que está faltando. O ajuste necessário é restabelecer o CO₂ usado na formação de matéria orgânica.",
          "isCorrect": false,
          "text": "Elevar a temperatura"
        },
        {
          "feedback": "Prolongar a iluminação oferece energia por mais tempo, mas continua sem fornecer matéria carbonada. A planta precisa que o CO₂ seja restabelecido.",
          "isCorrect": false,
          "text": "Iluminar por mais tempo"
        }
      ],
      "question": "Qual ajuste corrige a limitação indicada pelo sensor?"
    },
    {
      "dialogue": "Veja estas algas do tanque: elas usam a luz como fonte de energia e retiram CO₂ e água do ambiente para formar sua própria matéria orgânica.",
      "imagePrompt": "Tanque iluminado pelo Sol com algas verdes; setas simples mostram luz chegando às algas e CO₂ e água entrando nelas, sem apresentar comida sólida.",
      "options": [
        {
          "feedback": "As algas formam matéria orgânica usando matéria do ambiente e energia luminosa. Por isso, exercem o papel de produtoras.",
          "isCorrect": true,
          "text": "Produtoras"
        },
        {
          "feedback": "Consumidores obtêm matéria orgânica alimentando-se de outros seres. Estas algas formam sua própria matéria com CO₂, água e energia luminosa, portanto são produtoras.",
          "isCorrect": false,
          "text": "Consumidoras"
        },
        {
          "feedback": "Decompositores obtêm recursos ao degradar matéria orgânica de restos. Como as algas usam CO₂, água e luz para formar matéria orgânica, elas são produtoras.",
          "isCorrect": false,
          "text": "Decompositoras"
        },
        {
          "feedback": "O uso da luz não torna as algas consumidoras: luz é energia, não alimento ou matéria. Como formam matéria orgânica a partir de CO₂ e água, são produtoras.",
          "isCorrect": false,
          "text": "Produtoras-consumidoras"
        }
      ],
      "question": "Como essas algas devem ser classificadas?"
    },
    {
      "dialogue": "A cabra come capim, incorpora parte dessa matéria ao corpo e obtém energia química para se mover, crescer e manter suas funções vitais.",
      "imagePrompt": "Cabra comendo capim em um pasto; detalhe visual mostra folhas entrando pela boca e a cabra caminhando, sem setas de luz entrando diretamente no animal.",
      "options": [
        {
          "feedback": "A cabra obtém matéria e energia química ao consumir outro ser vivo. Essa forma de obtenção a classifica como consumidora.",
          "isCorrect": true,
          "text": "Consumidora"
        },
        {
          "feedback": "Produtores formam matéria orgânica usando fontes inorgânicas e uma fonte de energia. A cabra recebe matéria orgânica ao comer capim, portanto é consumidora.",
          "isCorrect": false,
          "text": "Produtora"
        },
        {
          "feedback": "Decompositores degradam restos e matéria orgânica morta. A cabra está ingerindo uma planta viva como alimento, o que a torna consumidora.",
          "isCorrect": false,
          "text": "Decompositora"
        },
        {
          "feedback": "Comer um produtor não faz o animal também produzir sua própria matéria orgânica a partir de CO₂ e água. A cabra continua sendo consumidora.",
          "isCorrect": false,
          "text": "Produtora-consumidora"
        }
      ],
      "question": "Qual papel metabólico corresponde à cabra?"
    },
    {
      "dialogue": "No pão esquecido, o fungo cresce enquanto quebra a matéria orgânica do alimento e absorve substâncias que usa como matéria e fonte de energia.",
      "imagePrompt": "Fatia de pão envelhecida com colônias visíveis de mofo crescendo e degradando a superfície; detalhe ampliado das hifas penetrando no pão.",
      "options": [
        {
          "feedback": "O fungo obtém matéria e energia ao degradar matéria orgânica do pão. Esse é o papel de um decompositor.",
          "isCorrect": true,
          "text": "Decompositor"
        },
        {
          "feedback": "Um produtor formaria matéria orgânica a partir de fontes inorgânicas. O fungo está degradando a matéria do pão, portanto atua como decompositor.",
          "isCorrect": false,
          "text": "Produtor"
        },
        {
          "feedback": "Consumidores ingerem outros organismos ou suas partes. Neste caso, o fungo libera substâncias sobre o pão e absorve os produtos da degradação, atuando como decompositor.",
          "isCorrect": false,
          "text": "Consumidor"
        },
        {
          "feedback": "A degradação do pão não produz matéria orgânica a partir de CO₂ e água. Ela caracteriza o fungo como decompositor, não como produtor-consumidor.",
          "isCorrect": false,
          "text": "Produtor-consumidor"
        }
      ],
      "question": "Que papel deve ser registrado para esse fungo?"
    },
    {
      "dialogue": "Durante o teste, o ciclista usa energia obtida dos nutrientes. Os sensores registram movimento dos pedais, aumento de calor e saída de CO₂ no ar expirado.",
      "imagePrompt": "Ciclista em bicicleta ergométrica conectada a sensores; pedais girando, termômetro corporal subindo e analisador do ar expirado exibindo CO₂.",
      "options": [
        {
          "feedback": "O giro dos pedais resulta da contração muscular produzindo movimento. Essa é a evidência direta de trabalho mecânico realizado pelo organismo.",
          "isCorrect": true,
          "text": "Pedais girando"
        },
        {
          "feedback": "A saída de CO₂ mostra eliminação de um resíduo do metabolismo. A evidência de trabalho mecânico é o movimento dos pedais causado pelos músculos.",
          "isCorrect": false,
          "text": "CO₂ sendo expirado"
        },
        {
          "feedback": "O aumento de calor é uma consequência das transformações de energia, mas não é o movimento procurado. Os pedais girando mostram diretamente o trabalho mecânico.",
          "isCorrect": false,
          "text": "Calor corporal aumentando"
        },
        {
          "feedback": "Nutrientes no sangue representam matéria disponível para as células, não a evidência direta de movimento. O trabalho mecânico aparece nos pedais girando.",
          "isCorrect": false,
          "text": "Nutrientes no sangue"
        }
      ],
      "question": "Qual registro evidencia diretamente o trabalho mecânico do organismo?"
    },
    {
      "dialogue": "O teste do aquário mostra alta concentração de resíduos nitrogenados eliminados pelos peixes. A água está turva, e precisamos reduzir esse acúmulo agora.",
      "imagePrompt": "Aquário com peixes e água levemente turva; kit de teste ao lado com escala legível indicando “resíduos nitrogenados: alto” e filtro em funcionamento.",
      "options": [
        {
          "feedback": "A troca parcial retira parte da água com resíduos e reduz sua concentração. Isso ajuda a compensar o acúmulo causado pela eliminação metabólica dos peixes.",
          "isCorrect": true,
          "text": "Trocar parte da água"
        },
        {
          "feedback": "Mais ração acrescentaria matéria ao aquário e poderia gerar ainda mais resíduos após o metabolismo dos peixes. A medida imediata é trocar parte da água.",
          "isCorrect": false,
          "text": "Aumentar a ração"
        },
        {
          "feedback": "Mais luz não remove os resíduos nitrogenados medidos na água. Para reduzir o acúmulo indicado pelo teste, deve-se trocar parte da água.",
          "isCorrect": false,
          "text": "Acender mais luz"
        },
        {
          "feedback": "Fechar a saída impede a circulação do filtro e não retira o material acumulado. A troca parcial da água reduz diretamente a concentração dos resíduos.",
          "isCorrect": false,
          "text": "Fechar a saída do filtro"
        }
      ],
      "question": "Qual ação reduz diretamente o problema indicado pelo teste?"
    }
  ]
}

