{
  "situations": [
    {
      "dialogue": "{{NAME}}, the prize spinner has four colored sections, but the draft sample space contains only three colors. We need an accurate list before calculating any chances.",
      "imagePrompt": "A prize spinner divided into four clearly visible colored sections: red, blue, green, and yellow. Beside it, a legible draft sample space reads “{red, green, yellow}.”",
      "options": [
        {
          "feedback": "The blue section is a possible result, so blue must be added. Then every spinner color appears exactly once in the sample space.",
          "isCorrect": true,
          "text": "Add blue"
        },
        {
          "feedback": "Red is visibly possible, so removing it would create another missing outcome. Add blue so all four possible colors are listed once.",
          "isCorrect": false,
          "text": "Remove red"
        },
        {
          "feedback": "Repeating yellow would duplicate an existing outcome while blue remained missing. Add blue to complete the sample space without duplication.",
          "isCorrect": false,
          "text": "Repeat yellow"
        },
        {
          "feedback": "The listed colors represent individual outcomes, so combining two of them would hide possible results. Add blue to list all four colors separately.",
          "isCorrect": false,
          "text": "Merge red and green"
        }
      ],
      "question": "What correction should be made first?"
    },
    {
      "dialogue": "A standard six-sided die was used, and the analyst entered the sample space as `{1, 2, 3, 4, 4, 6}`. The list must contain each possible face exactly once.",
      "imagePrompt": "A standard six-sided die beside a computer screen showing the large, legible list “{1, 2, 3, 4, 4, 6}.” The two entries of 4 are visibly highlighted.",
      "options": [
        {
          "feedback": "This removes the repeated 4 and restores the missing face 5. The resulting list contains every possible die result exactly once.",
          "isCorrect": true,
          "text": "Replace second 4 with 5"
        },
        {
          "feedback": "Adding 5 restores the missing face, but 4 would still appear twice. Replace the second 4 with 5 to fix both errors.",
          "isCorrect": false,
          "text": "Add 5 at the end"
        },
        {
          "feedback": "Deleting the repeated 4 removes the duplication, but face 5 would still be absent. Replace that second 4 with 5 instead.",
          "isCorrect": false,
          "text": "Delete the second 4"
        },
        {
          "feedback": "Changing 6 to 5 would remove a possible face while leaving 4 duplicated. Replace the second 4 with 5 so faces 1 through 6 each appear once.",
          "isCorrect": false,
          "text": "Replace 6 with 5"
        }
      ],
      "question": "Which correction fixes the entire sample space?"
    },
    {
      "dialogue": "The inspection system records whether each metal panel has a scratch, a dent, both defects, or neither. Its current labels are `no defect`, `scratched`, and `dented`, but one panel can match two labels.",
      "imagePrompt": "Four metal panels shown clearly: one with no defect, one with only a scratch, one with only a dent, and one with both a scratch and a dent. Beside them are the labels “no defect,” “scratched,” and “dented,” with the both-defects panel connected to two labels.",
      "options": [
        {
          "feedback": "These four labels cover every observed condition, and the word “only” prevents the scratch and dent categories from overlapping. Each panel fits exactly one outcome.",
          "isCorrect": true,
          "text": "Neither / scratch only / dent only / both"
        },
        {
          "feedback": "A panel with both defects would still fit both “scratched” and “dented,” so the outcomes overlap. Use neither, scratch only, dent only, and both.",
          "isCorrect": false,
          "text": "Neither / scratched / dented / both"
        },
        {
          "feedback": "The labels do not overlap, but they omit panels with both defects. Add a separate “both” outcome to the three exclusive conditions.",
          "isCorrect": false,
          "text": "Neither / scratch only / dent only"
        },
        {
          "feedback": "A dented panel without a scratch would be included under “not scratched,” while “dented” names it again. Use neither, scratch only, dent only, and both to avoid overlap.",
          "isCorrect": false,
          "text": "Scratched / not scratched / dented"
        }
      ],
      "question": "Which replacement creates nonoverlapping outcomes and includes every panel?"
    },
    {
      "dialogue": "We toss a coin twice and record the first and second results in order. Before analyzing the results, we need the complete sample space for the two recorded positions.",
      "imagePrompt": "Two coins arranged left to right and labeled “first toss” and “second toss.” Below them are four empty result boxes intended for ordered two-letter outcomes using H and T.",
      "options": [
        {
          "feedback": "The four ordered pairs cover every possible first-and-second-toss result exactly once. `HT` and `TH` remain separate because they occur in different orders.",
          "isCorrect": true,
          "text": "`{HH, HT, TH, TT}`"
        },
        {
          "feedback": "This omits `TH`, which is possible when the first toss is tails and the second is heads. The complete ordered sample space is `{HH, HT, TH, TT}`.",
          "isCorrect": false,
          "text": "`{HH, HT, TT}`"
        },
        {
          "feedback": "This treats “one head” as a single outcome and loses the recorded order. Because `HT` and `TH` are distinct records, use `{HH, HT, TH, TT}`.",
          "isCorrect": false,
          "text": "`{HH, one head, TT}`"
        },
        {
          "feedback": "The list includes both ordered mixed results, but `HH` is duplicated. The sample space should be `{HH, HT, TH, TT}`, with each result appearing once.",
          "isCorrect": false,
          "text": "`{HH, HT, TH, TT, HH}`"
        }
      ],
      "question": "Which list is the valid sample space?"
    },
    {
      "dialogue": "{{NAME}}, a delivery trial has the verified sample space `{Monday, Tuesday, Wednesday, Thursday, Friday}`. The service team now wants the event “delivery after Wednesday.”",
      "imagePrompt": "A delivery dashboard showing the verified sample space “{Monday, Tuesday, Wednesday, Thursday, Friday}.” Below it, a calendar row displays those five weekdays in order, with no days highlighted.",
      "options": [
        {
          "feedback": "Within the verified sample space, the days after Wednesday are Thursday and Friday. Those two outcomes form the requested event.",
          "isCorrect": true,
          "text": "`{Thursday, Friday}`"
        },
        {
          "feedback": "Wednesday is not after Wednesday. The event must contain only Thursday and Friday, the later outcomes in the sample space.",
          "isCorrect": false,
          "text": "`{Wednesday, Thursday, Friday}`"
        },
        {
          "feedback": "Monday through Wednesday describe delivery on or before Wednesday. Delivery after Wednesday corresponds to `{Thursday, Friday}`.",
          "isCorrect": false,
          "text": "`{Monday, Tuesday, Wednesday}`"
        },
        {
          "feedback": "Friday is after Wednesday, but Thursday is also after Wednesday and cannot be omitted. The complete event is `{Thursday, Friday}`.",
          "isCorrect": false,
          "text": "`{Friday}`"
        }
      ],
      "question": "Which outcomes belong to that event?"
    }
  ]
}

